import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface Feedback {
  id: string;
  sentiment: string;
  comment: string;
}

interface WidgetData {
  npsScore: number;
  trend: number[];
  recentFeedback: Feedback[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { npsScore, trend, recentFeedback } = widgetData;
  const positiveFeedback = recentFeedback.filter(feedback => feedback.sentiment === 'positive').length;
  const neutralFeedback = recentFeedback.filter(feedback => feedback.sentiment === 'neutral').length;
  const negativeFeedback = recentFeedback.filter(feedback => feedback.sentiment === 'negative').length;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1A1A1B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#39FF14' }}>
              NPS Score
            </Typography>
            <Typography variant="h3" sx={{ color: '#E0115F', fontWeight: 600 }}>
              {npsScore}
            </Typography>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: trend,
                color: '#39FF14',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: trend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            <Chip label={`Positive: ${positiveFeedback}`} sx={{ fontSize: '11px', bgcolor: '#39FF14', color: '#1A1A1B' }} />
            <Chip label={`Neutral: ${neutralFeedback}`} sx={{ fontSize: '11px', bgcolor: '#FFD700', color: '#1A1A1B' }} />
            <Chip label={`Negative: ${negativeFeedback}`} sx={{ fontSize: '11px', bgcolor: '#FF4500', color: '#1A1A1B' }} />
          </Stack>

          <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
            Recent Feedback:
          </Typography>
          {recentFeedback.slice(0, 3).map(feedback => (
            <Typography key={feedback.id} variant="caption" sx={{ color: '#C0C0C0' }}>
              - {feedback.comment}
            </Typography>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
